 1	import { type K8sModel, useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
 2	
 3	import type { ProvidersPermissionStatus } from '../utils/types/ProvidersPermissionStatus';
 4	
 5	/**
 6	 * Type for the parameters of the useGetDeleteAndEditAccessReview custom hook.
 7	 *
 8	 * @typedef {Object} K8sModelAccessReviewParams
 9	 * @property {K8sModel} model - The Kubernetes model to check permissions on.
10	 * @property {string} [name] - The name of the specific instance of the model, if any.
11	 * @property {string} [namespace] - The namespace in which to review access permissions.
12	 */
13	type K8sModelAccessReviewParams = {
14	  model: K8sModel;
15	  name?: string;
16	  namespace?: string;
17	};
18	
19	/**
20	 * A React hook that checks permissions for different actions on a Kubernetes model within a specified namespace.
21	 * @param {K8sModelAccessReviewParams} param0 - An object that contains model, name and namespace details.
22	 * @returns {Object} An object containing permissions and a loading state.
23	 */
24	const useGetDeleteAndEditAccessReview: UseAccessReviewFn = ({ model, name, namespace }) => {
25	  const [canCreate, loadingCreate] = useAccessReview({
26	    group: model.apiGroup,
27	    namespace,
28	    resource: model.plural,
29	    verb: 'create',
30	  });
31	
32	  const [canPatch, loadingPatch] = useAccessReview({
33	    group: model.apiGroup,
34	    name,
35	    namespace,
36	    resource: model.plural,
37	    verb: 'patch',
38	  });
39	
40	  const [canDelete, loadingDelete] = useAccessReview({
41	    group: model.apiGroup,
42	    name,
43	    namespace,
44	    resource: model.plural,
45	    verb: 'delete',
46	  });
47	
48	  const [canGet, loadingGet] = useAccessReview({
49	    group: model.apiGroup,
50	    name,
51	    namespace,
52	    resource: model.plural,
53	    verb: 'get',
54	  });
55	
56	  return {
57	    canCreate,
58	    canDelete,
59	    canGet,
60	    canPatch,
61	    loading: loadingCreate || loadingPatch || loadingDelete || loadingGet,
62	  };
63	};
64	
65	type UseAccessReviewFn = (props: K8sModelAccessReviewParams) => ProvidersPermissionStatus;
66	
67	export default useGetDeleteAndEditAccessReview;

